// Helper to convert hex string to Uint8Array
function hexToBytes(hex) {
    const bytes = new Uint8Array(hex.length / 2);
    for (let i = 0; i < bytes.length; i++) {
        bytes[i] = parseInt(hex.substr(i * 2, 2), 16);
    }
    return bytes;
}

// Helper to convert Uint8Array to hex string
function bytesToHex(bytes) {
    return Array.from(bytes).map(b => b.toString(16).padStart(2, '0')).join('');
}

// Encrypt data using key material derived from password
async function encryptData(plaintext, keyMaterial) {
    const encoder = new TextEncoder();
    const salt = window.crypto.getRandomValues(new Uint8Array(16));
    const iv = window.crypto.getRandomValues(new Uint8Array(12));

    const baseKey = await window.crypto.subtle.importKey(
        "raw",
        encoder.encode(keyMaterial),
        "PBKDF2",
        false,
        ["deriveKey"]
    );

    const aesKey = await window.crypto.subtle.deriveKey(
        {
            name: "PBKDF2",
            salt: salt,
            iterations: 100000,
            hash: "SHA-256"
        },
        baseKey,
        { name: "AES-GCM", length: 256 },
        false,
        ["encrypt"]
    );

    const ciphertextBuffer = await window.crypto.subtle.encrypt(
        {
            name: "AES-GCM",
            iv: iv,
            tagLength: 128
        },
        aesKey,
        encoder.encode(plaintext)
    );

    const encryptedBytes = new Uint8Array(ciphertextBuffer);
    const tag = encryptedBytes.slice(encryptedBytes.length - 16);
    const ciphertext = encryptedBytes.slice(0, encryptedBytes.length - 16);

    return {
        salt: bytesToHex(salt),
        iv: bytesToHex(iv),
        tag: bytesToHex(tag),
        ciphertext: bytesToHex(ciphertext)
    };
}

// Decrypt data using key material derived from password
async function decryptData(encryptedObj, keyMaterial) {
    const encoder = new TextEncoder();
    try {
        const baseKey = await window.crypto.subtle.importKey(
            "raw",
            encoder.encode(keyMaterial),
            "PBKDF2",
            false,
            ["deriveKey"]
        );

        const salt = hexToBytes(encryptedObj.salt);
        const iv = hexToBytes(encryptedObj.iv);
        const ciphertext = hexToBytes(encryptedObj.ciphertext);
        const tag = hexToBytes(encryptedObj.tag);

        const encryptedData = new Uint8Array(ciphertext.length + tag.length);
        encryptedData.set(ciphertext);
        encryptedData.set(tag, ciphertext.length);

        const aesKey = await window.crypto.subtle.deriveKey(
            {
                name: "PBKDF2",
                salt: salt,
                iterations: 100000,
                hash: "SHA-256"
            },
            baseKey,
            { name: "AES-GCM", length: 256 },
            false,
            ["decrypt"]
        );

        const decryptedBuffer = await window.crypto.subtle.decrypt(
            {
                name: "AES-GCM",
                iv: iv,
                tagLength: 128
            },
            aesKey,
            encryptedData
        );

        return new TextDecoder().decode(decryptedBuffer);
    } catch (e) {
        console.error("Custom data decryption failed:", e);
        return null;
    }
}

// Decrypt the default database
async function decryptDatabase(username, password) {
    const encoder = new TextEncoder();
    const keyMaterial = `${username}:${password}`;

    const baseKey = await window.crypto.subtle.importKey(
        "raw",
        encoder.encode(keyMaterial),
        "PBKDF2",
        false,
        ["deriveKey"]
    );

    const salt = hexToBytes(ENCRYPTED_DATABASE.salt);
    const iv = hexToBytes(ENCRYPTED_DATABASE.iv);
    const ciphertext = hexToBytes(ENCRYPTED_DATABASE.ciphertext);
    const tag = hexToBytes(ENCRYPTED_DATABASE.tag);

    const encryptedData = new Uint8Array(ciphertext.length + tag.length);
    encryptedData.set(ciphertext);
    encryptedData.set(tag, ciphertext.length);

    const aesKey = await window.crypto.subtle.deriveKey(
        {
            name: "PBKDF2",
            salt: salt,
            iterations: 100000,
            hash: "SHA-256"
        },
        baseKey,
        { name: "AES-GCM", length: 256 },
        false,
        ["decrypt"]
    );

    const decryptedBuffer = await window.crypto.subtle.decrypt(
        {
            name: "AES-GCM",
            iv: iv,
            tagLength: 128
        },
        aesKey,
        encryptedData
    );

    const decoded = new TextDecoder().decode(decryptedBuffer);
    return JSON.parse(decoded);
}

// Load systems from localStorage or decrypt default database
async function loadSystems() {
    const sessionKey = sessionStorage.getItem('erp_session_key');
    if (!sessionKey) return;

    try {
        const stored = localStorage.getItem('custom_erp_systems');
        if (stored) {
            const decrypted = await decryptData(JSON.parse(stored), sessionKey);
            if (decrypted) {
                systems = JSON.parse(decrypted);
                return;
            }
        }
        systems = JSON.parse(JSON.stringify(defaultSystems));
    } catch (e) {
        console.error("Error loading systems from localStorage", e);
        systems = JSON.parse(JSON.stringify(defaultSystems));
    }
}

// Login handler
async function handleLogin(event) {
    event.preventDefault();
    const usernameInput = document.getElementById('usernameInput');
    const passwordInput = document.getElementById('passwordInput');
    const loginError = document.getElementById('loginError');

    const username = usernameInput.value.trim();
    const password = passwordInput.value;

    if (username !== 'WMGSME') {
        loginError.textContent = "Invalid username or password";
        loginError.style.display = 'block';
        return;
    }

    try {
        loginError.style.display = 'none';
        const decrypted = await decryptDatabase(username, password);

        defaultSystems = decrypted;
        sessionStorage.setItem('erp_session_key', `${username}:${password}`);

        await loadSystems();
        setupCategoryMultiSelectDropdown();

        document.getElementById('loginOverlay').style.display = 'none';
        document.getElementById('mainContainer').style.display = 'flex';

        setupFilters();
        displaySystems(systems);

    } catch (err) {
        console.error("Authentication failed:", err);
        loginError.textContent = "Invalid username or password";
        loginError.style.display = 'block';

        const loginCard = document.querySelector('.login-card');
        loginCard.style.animation = 'none';
        loginCard.offsetHeight; // trigger reflow
        loginCard.style.animation = 'shake 0.3s ease-in-out';
    }
}
window.handleLogin = handleLogin;

