// Theme toggle logic
function toggleTheme() {
    const currentTheme = document.documentElement.getAttribute('data-theme') || 'light';
    const newTheme = currentTheme === 'dark' ? 'light' : 'dark';

    document.documentElement.setAttribute('data-theme', newTheme);
    localStorage.setItem('theme', newTheme);

    const btn = document.getElementById('themeToggleBtn');
    if (btn) {
        btn.textContent = newTheme === 'dark' ? '☀️' : '🌙';
        btn.title = newTheme === 'dark' ? 'Toggle light mode' : 'Toggle dark mode';
        btn.setAttribute('aria-label', newTheme === 'dark' ? 'Toggle light mode' : 'Toggle dark mode');
    }
}
window.toggleTheme = toggleTheme;

// Initialize Application
async function init() {
    // Initialize Theme Toggle Button state and event listener
    const savedTheme = document.documentElement.getAttribute('data-theme') || 'light';
    const themeBtn = document.getElementById('themeToggleBtn');
    if (themeBtn) {
        themeBtn.textContent = savedTheme === 'dark' ? '☀️' : '🌙';
        themeBtn.title = savedTheme === 'dark' ? 'Toggle light mode' : 'Toggle dark mode';
        themeBtn.setAttribute('aria-label', savedTheme === 'dark' ? 'Toggle light mode' : 'Toggle dark mode');
        themeBtn.addEventListener('click', toggleTheme);
    }

    setupMultiSelectDropdown();
    setupCategoryMultiSelectDropdown();
    setupCSVToolbar();
    setupModal();

    // Bind Log Out button
    const btnLogout = document.getElementById('btnLogout');
    if (btnLogout) {
        btnLogout.addEventListener('click', logout);
    }

    // Check if session is already active
    const sessionKey = sessionStorage.getItem('erp_session_key');
    if (sessionKey) {
        const parts = sessionKey.split(':');
        const username = parts[0];
        const password = parts.slice(1).join(':');

        try {
            const decrypted = await decryptDatabase(username, password);
            defaultSystems = decrypted;
            await loadSystems();
            setupCategoryMultiSelectDropdown();

            document.getElementById('loginOverlay').style.display = 'none';
            document.getElementById('mainContainer').style.display = 'flex';

            setupFilters();
            displaySystems(systems);
        } catch (e) {
            console.error("Auto-login failed:", e);
            sessionStorage.removeItem('erp_session_key');
            showLoginForm();
        }
    } else {
        showLoginForm();
    }
}

function showLoginForm() {
    document.getElementById('loginOverlay').style.display = 'flex';
    document.getElementById('mainContainer').style.display = 'none';
}

// Display Systems Cards
// Display Systems (handles both Grid Cards and Market Position Bubble Chart)
function displaySystems(systemsToDisplay) {
    const gridContainer = document.getElementById('systemsContainer');
    const chartContainer = document.getElementById('chartContainer');
    const resultCountEl = document.getElementById('resultCount');

    // Update result count in stats bar
    if (resultCountEl) {
        resultCountEl.textContent = systemsToDisplay.length;
    }

    if (currentView === 'grid') {
        gridContainer.style.display = 'grid';
        chartContainer.style.display = 'none';

        gridContainer.innerHTML = '';
        if (systemsToDisplay.length === 0) {
            gridContainer.innerHTML = '<div class="no-results">No ERP or MRP systems match your selected filters. Try adjusting your criteria.</div>';
            return;
        }

        systemsToDisplay.forEach(system => {
            const card = createSystemCard(system);
            gridContainer.appendChild(card);
        });
    } else {
        gridContainer.style.display = 'none';
        chartContainer.style.display = 'grid';
        renderMarketPositionChart(systemsToDisplay);
    }
}

// View switching controller
window.switchView = function (view) {
    currentView = view;

    if (view === 'chart') {
        zoomScale = 1;
        panX = 0;
        panY = 0;
    }

    const btnGrid = document.getElementById('btnGridView');
    const btnChart = document.getElementById('btnChartView');

    if (view === 'grid') {
        if (btnGrid) {
            btnGrid.classList.add('active');
            btnGrid.classList.remove('btn-outline');
        }
        if (btnChart) {
            btnChart.classList.remove('active');
            btnChart.classList.add('btn-outline');
        }
    } else {
        if (btnChart) {
            btnChart.classList.add('active');
            btnChart.classList.remove('btn-outline');
        }
        if (btnGrid) {
            btnGrid.classList.remove('active');
            btnGrid.classList.add('btn-outline');
        }
    }

    filterSystems();
};

// Ensure all systems have valid coordinates
function ensureSystemCoordinates(system) {
    if (system.idcCapabilities === undefined || system.idcStrategies === undefined || system.idcMarketShare === undefined) {
        let cap = 50;
        let strat = 50;
        let share = 25;

        if (system.size === 'enterprise') share = 80;
        else if (system.size === 'midmarket') share = 50;

        const primaryCat = (system.categories && system.categories[0]) || "";
        switch (primaryCat) {
            case "Enterprise Solutions":
                cap = 80; strat = 80;
                break;
            case "Mid-Market Cloud":
                cap = 70; strat = 70;
                break;
            case "Small Business":
                cap = 55; strat = 55;
                break;
            default:
                cap = 60; strat = 60;
                break;
        }

        if (system.location === 'UK Native') cap += 5;
        else if (system.location === 'UK Support') cap += 2;

        if (system.financialStability === 'Safe') { cap += 5; strat += 5; }
        else if (system.financialStability === 'Stable') { cap += 3; strat += 3; }

        system.idcCapabilities = cap;
        system.idcStrategies = strat;
        system.idcMarketShare = share;
    }
}

// Render the Market Position SVG Chart
function renderMarketPositionChart(systemsToDisplay) {
    const wrapper = document.querySelector('#chartContainer .chart-wrapper');
    if (!wrapper) return;

    wrapper.innerHTML = '';

    let tooltip = document.getElementById('chartTooltip');
    if (!tooltip) {
        tooltip = document.createElement('div');
        tooltip.id = 'chartTooltip';
        tooltip.className = 'chart-tooltip';
        document.body.appendChild(tooltip);
    }

    const svgWidth = 800;
    const svgHeight = 600;

    const categoryColors = {
        "Enterprise Solutions": { fill: "rgba(0, 82, 204, 0.65)", stroke: "#0052cc" },
        "Mid-Market Cloud": { fill: "rgba(2, 136, 209, 0.65)", stroke: "#0288d1" },
        "Small Business": { fill: "rgba(71, 85, 105, 0.65)", stroke: "#475569" },
        "Specialized Solutions": { fill: "rgba(123, 31, 162, 0.65)", stroke: "#7b1fa2" },
        "Job Shop": { fill: "rgba(230, 81, 0, 0.65)", stroke: "#e65100" },
        "Open Source": { fill: "rgba(46, 125, 50, 0.65)", stroke: "#2e7d32" },
        "SCADA": { fill: "rgba(109, 40, 217, 0.65)", stroke: "#6d28d9" },
        "MES": { fill: "rgba(139, 92, 246, 0.65)", stroke: "#8b5cf6" },
        "IIoT Solutions": { fill: "rgba(79, 70, 229, 0.65)", stroke: "#4f46e5" },
        "default": { fill: "rgba(101, 163, 13, 0.65)", stroke: "#65a30d" }
    };

    let bubbleElementsHTML = '';
    systemsToDisplay.forEach(system => {
        ensureSystemCoordinates(system);

        const strategies = system.idcStrategies;
        const capabilities = system.idcCapabilities;
        const marketShare = system.idcMarketShare;

        // Map 10-100 values to coordinate space
        const cx = 80 + ((strategies - 10) / 90) * 670;
        const cy = 550 - ((capabilities - 10) / 90) * 500;
        const r = 6 + ((marketShare - 10) / 90) * 18;

        const primaryCategory = (system.categories || []).find(cat => categoryColors[cat]) || "default";
        const colorSet = categoryColors[primaryCategory] || categoryColors["default"];
        const categoriesJoined = (system.categories || []).join(', ');

        bubbleElementsHTML += `
            <g class="bubble-group" 
               data-name="${escapeHTML(system.name)}"
               data-category="${escapeHTML(categoriesJoined)}"
               data-cap="${capabilities}"
               data-strat="${strategies}"
               data-share="${marketShare}"
               data-size="${system.size}"
               data-cx="${cx}"
               data-cy="${cy}"
               onclick="window.openSystemDetailsModal('${escapeJS(system.name)}')"
            >
                <circle cx="${cx}" cy="${cy}" r="${r}" 
                        fill="${colorSet.fill}" 
                        stroke="${colorSet.stroke}" 
                        class="bubble-circle">
                </circle>
                <text x="${cx + r + 5}" y="${cy + 3}" class="bubble-label">${escapeHTML(system.name)}</text>
            </g>
        `;
    });

    const svgHTML = `
        <svg viewBox="0 0 ${svgWidth} ${svgHeight}" class="chart-svg" width="100%" height="100%" style="user-select: none;">
            <defs>
                <!-- Clip path to keep panned/zoomed graphics strictly within the plottable grid boundaries -->
                <clipPath id="chartClip">
                    <rect x="80" y="50" width="670" height="500" />
                </clipPath>
            </defs>

            <!-- Zoomable Group (Contains background bands, grids, labels and bubbles) -->
            <g id="zoomableGroup" clip-path="url(#chartClip)" transform="translate(${panX}, ${panY}) scale(${zoomScale})">
                <!-- Concentric Background Zones -->
                <rect x="80" y="50" width="670" height="500" class="zone-path-participants" />
                <path d="M 800 0 L 50 0 A 750 750 0 0 0 800 750 Z" class="zone-path-contenders" />
                <path d="M 800 0 L 250 0 A 550 550 0 0 0 800 550 Z" class="zone-path-players" />
                <path d="M 800 0 L 500 0 A 300 300 0 0 0 800 300 Z" class="zone-path-leaders" />
                
                <!-- Zone Boundary Arcs -->
                <path d="M 50 0 A 750 750 0 0 0 800 750" fill="none" class="zone-line" />
                <path d="M 250 0 A 550 550 0 0 0 800 550" fill="none" class="zone-line" />
                <path d="M 500 0 A 300 300 0 0 0 800 300" fill="none" class="zone-line" />
                
                <!-- Zone Labels -->
                <text x="690" y="70" class="zone-title" text-anchor="middle" transform="rotate(15, 690, 70)">Leaders</text>
                <text x="530" y="210" class="zone-title" text-anchor="middle" transform="rotate(15, 530, 210)">Major Players</text>
                <text x="360" y="370" class="zone-title" text-anchor="middle" transform="rotate(15, 360, 370)">Contenders</text>
                <text x="180" y="520" class="zone-title" text-anchor="middle" transform="rotate(15, 180, 520)">Participants</text>
                
                <!-- Grid Lines -->
                <line x1="214" y1="50" x2="214" y2="550" class="grid-line" />
                <line x1="348" y1="50" x2="348" y2="550" class="grid-line" />
                <line x1="482" y1="50" x2="482" y2="550" class="grid-line" />
                <line x1="616" y1="50" x2="616" y2="550" class="grid-line" />
                
                <line x1="80" y1="450" x2="750" y2="450" class="grid-line" />
                <line x1="80" y1="350" x2="750" y2="350" class="grid-line" />
                <line x1="80" y1="250" x2="750" y2="250" class="grid-line" />
                <line x1="80" y1="150" x2="750" y2="150" class="grid-line" />
                
                <!-- Bubbles container -->
                <g id="svgBubblesContainer">
                    ${bubbleElementsHTML}
                </g>
            </g>
            
            <!-- Static Foreground Frame (Axis lines and external labels remain fixed) -->
            <!-- Axis lines -->
            <line x1="80" y1="550" x2="750" y2="550" class="axis-line" />
            <line x1="80" y1="50" x2="80" y2="550" class="axis-line" />
            
            <!-- Axis titles -->
            <text x="30" y="300" class="axis-title" text-anchor="middle" transform="rotate(-90, 30, 300)">Capabilities →</text>
            <text x="415" y="585" class="axis-title" text-anchor="middle">Strategies →</text>
            
            <!-- Axis markers -->
            <text x="70" y="544" class="chart-label" text-anchor="end">Low (10)</text>
            <text x="70" y="58" class="chart-label" text-anchor="end">High (100)</text>
            <text x="80" y="568" class="chart-label" text-anchor="middle">Low (10)</text>
            <text x="750" y="568" class="chart-label" text-anchor="middle">High (100)</text>
        </svg>
    `;

    wrapper.innerHTML = svgHTML + `
        <!-- HTML zoom controls are layered in index.html to ensure absolute positioning -->
    `;

    // Bind pan and zoom mouse listeners to the SVG canvas
    const svg = wrapper.querySelector('.chart-svg');
    let isDragging = false;
    let startX = 0, startY = 0;
    let clickStartX = 0, clickStartY = 0;

    function updateTransform() {
        // Enforce boundary constraints to prevent blank spaces when panning or zooming
        zoomScale = Math.max(1, Math.min(5, zoomScale));

        const minPanX = 750 * (1 - zoomScale);
        const maxPanX = 80 * (1 - zoomScale);
        panX = Math.min(maxPanX, Math.max(minPanX, panX));

        const minPanY = 550 * (1 - zoomScale);
        const maxPanY = 50 * (1 - zoomScale);
        panY = Math.min(maxPanY, Math.max(minPanY, panY));

        const zoomGroup = svg.querySelector('#zoomableGroup');
        if (zoomGroup) {
            zoomGroup.setAttribute('transform', `translate(${panX}, ${panY}) scale(${zoomScale})`);
        }

        // Counter-scale all bubbles to keep their physical size and text crisp and readable
        const invScale = 1 / zoomScale;
        const bubbles = svg.querySelectorAll('.bubble-group');
        bubbles.forEach(b => {
            const cx = parseFloat(b.getAttribute('data-cx'));
            const cy = parseFloat(b.getAttribute('data-cy'));
            b.setAttribute('transform', `translate(${cx}, ${cy}) scale(${invScale}) translate(${-cx}, ${-cy})`);
        });
    }

    svg.addEventListener('mousedown', (e) => {
        if (e.button !== 0) return; // Only allow left-click drag
        isDragging = true;
        startX = e.clientX - panX;
        startY = e.clientY - panY;
        clickStartX = e.clientX;
        clickStartY = e.clientY;
        svg.style.cursor = 'grabbing';
    });

    svg.addEventListener('mousemove', (e) => {
        if (!isDragging) return;
        panX = e.clientX - startX;
        panY = e.clientY - startY;
        updateTransform();
    });

    const endDrag = (e) => {
        if (!isDragging) return;
        isDragging = false;
        svg.style.cursor = 'default';
        const dx = e.clientX - clickStartX;
        const dy = e.clientY - clickStartY;
        dragDistance = Math.sqrt(dx * dx + dy * dy);
    };

    svg.addEventListener('mouseup', endDrag);
    svg.addEventListener('mouseleave', endDrag);

    svg.addEventListener('wheel', (e) => {
        e.preventDefault();
        const zoomFactor = 1.1;
        const rect = svg.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;

        const prevScale = zoomScale;
        if (e.deltaY < 0) {
            zoomScale = Math.min(5, zoomScale * zoomFactor);
        } else {
            zoomScale = Math.max(1, zoomScale / zoomFactor); // Min zoom is 1.0
        }

        // Offset panning to keep target location under zoom
        panX = mouseX - (mouseX - panX) * (zoomScale / prevScale);
        panY = mouseY - (mouseY - panY) * (zoomScale / prevScale);

        updateTransform();
    });

    // Bind Overlay Control Buttons
    window.zoomChart = function (factor) {
        const prevScale = zoomScale;
        zoomScale = Math.min(5, Math.max(1, zoomScale * factor));

        const centerX = 415;
        const centerY = 300;

        panX = centerX - (centerX - panX) * (zoomScale / prevScale);
        panY = centerY - (centerY - panY) * (zoomScale / prevScale);

        updateTransform();
    };

    window.resetChartZoom = function () {
        zoomScale = 1;
        panX = 0;
        panY = 0;
        updateTransform();
    };

    // Ensure initial transform is properly constrained and counter-scaled
    updateTransform();

    // Bind hover listeners for tooltips
    const bubbleGroups = wrapper.querySelectorAll('.bubble-group');
    bubbleGroups.forEach(group => {
        group.addEventListener('mouseenter', (e) => {
            const name = group.getAttribute('data-name');
            const category = group.getAttribute('data-category');
            const cap = group.getAttribute('data-cap');
            const strat = group.getAttribute('data-strat');
            const share = group.getAttribute('data-share');
            const size = group.getAttribute('data-size');

            tooltip.style.display = 'flex';
            tooltip.innerHTML = `
                <div class="tooltip-header">${name}</div>
                <div class="tooltip-category">${category}</div>
                <div class="tooltip-stat"><span>Capabilities:</span> <span>${cap}/100</span></div>
                <div class="tooltip-stat"><span>Strategies:</span> <span>${strat}/100</span></div>
                <div class="tooltip-stat"><span>Market Share:</span> <span>${share}/100</span></div>
                <div class="tooltip-stat"><span>Target Size:</span> <span>${size.toUpperCase()}</span></div>
                <div class="tooltip-footer">Click bubble to view details</div>
            `;

            tooltip.style.left = (e.pageX + 15) + 'px';
            tooltip.style.top = (e.pageY + 15) + 'px';
        });

        group.addEventListener('mousemove', (e) => {
            tooltip.style.left = (e.pageX + 15) + 'px';
            tooltip.style.top = (e.pageY + 15) + 'px';
        });

        group.addEventListener('mouseleave', () => {
            tooltip.style.display = 'none';
        });
    });
}

// Unified System details modal (System Evaluation Notes + UK Resellers)
