function saveNewVendor(event) {
    event.preventDefault();

    const name = document.getElementById('newVendorName').value.trim();
    const size = document.getElementById('newVendorSize').value;
    const deployment = document.getElementById('newVendorDeployment').value.trim();
    const location = document.getElementById('newVendorLocation').value;
    const stability = document.getElementById('newVendorStability').value;
    const website = document.getElementById('newVendorWebsite').value.trim();
    const email = document.getElementById('newVendorEmail').value.trim();
    const phone = document.getElementById('newVendorPhone').value.trim();

    // Read Categories checkboxes
    const categoryElements = document.querySelectorAll('.new-vendor-category:checked');
    const categories = Array.from(categoryElements).map(el => el.value);

    if (categories.length === 0) {
        alert("Please select at least one Category for the vendor.");
        return;
    }

    // Read IDC coordinates
    const idcCapabilities = parseInt(document.getElementById('newVendorCapabilities').value) || 65;
    const idcStrategies = parseInt(document.getElementById('newVendorStrategies').value) || 65;
    const idcMarketShare = parseInt(document.getElementById('newVendorMarketShare').value) || 30;

    // Sectors
    const sectorElements = document.querySelectorAll('.new-vendor-sector:checked');
    const sectors = Array.from(sectorElements).map(el => el.value);

    // Strengths
    const strengthsText = document.getElementById('newVendorStrengths').value;
    const strengths = strengthsText.split('\n')
        .map(s => s.trim())
        .filter(s => s.length > 0);

    // VARs
    const varRows = document.querySelectorAll('.new-var-row');
    const ukVars = [];
    varRows.forEach(row => {
        const varName = row.querySelector('.var-name-input').value.trim();
        const varWebsite = row.querySelector('.var-website-input').value.trim();
        const varDesc = row.querySelector('.var-desc-input').value.trim();
        if (varName) {
            ukVars.push({
                name: varName,
                description: varDesc || "Authorized partner in the UK.",
                website: varWebsite || ""
            });
        }
    });

    const newSystem = {
        name,
        categories,
        sectors,
        size,
        deployment,
        location,
        financialStability: stability,
        strengths,
        contact: {
            website,
            email,
            phone
        },
        ukVars,
        idcCapabilities,
        idcStrategies,
        idcMarketShare
    };

    if (activeSystemForEdit) {
        const editIdx = systems.findIndex(s => s.name.toLowerCase() === activeSystemForEdit.toLowerCase());
        if (editIdx !== -1) {
            // If name has changed, migrate localStorage notes to the new keys
            if (activeSystemForEdit.toLowerCase() !== name.toLowerCase()) {
                const oldKey = getERPNotesKey(activeSystemForEdit);
                const newKey = getERPNotesKey(name);
                const notes = localStorage.getItem(oldKey);
                if (notes) {
                    localStorage.setItem(newKey, notes);
                    localStorage.removeItem(oldKey);
                }

                const oldSystem = systems[editIdx];
                if (oldSystem && oldSystem.ukVars) {
                    oldSystem.ukVars.forEach(v => {
                        const oldVarKey = getVARNotesKey(activeSystemForEdit, v.name);
                        const varNotes = localStorage.getItem(oldVarKey);
                        if (varNotes) {
                            const newVarKey = getVARNotesKey(name, v.name);
                            localStorage.setItem(newVarKey, varNotes);
                            localStorage.removeItem(oldVarKey);
                        }
                    });
                }
            }

            // Check if they are renaming to an already existing name (excluding the edited one)
            const dupIdx = systems.findIndex(s => s.name.toLowerCase() === name.toLowerCase());
            if (dupIdx !== -1 && dupIdx !== editIdx) {
                if (!confirm(`A vendor named "${name}" already exists. Do you want to overwrite it?`)) {
                    return;
                }
                systems[dupIdx] = newSystem;
                systems.splice(editIdx, 1);
            } else {
                systems[editIdx] = newSystem;
            }
        } else {
            systems.push(newSystem);
        }
    } else {
        const existingIdx = systems.findIndex(s => s.name.toLowerCase() === name.toLowerCase());
        if (existingIdx !== -1) {
            if (!confirm(`A vendor named "${name}" already exists. Do you want to overwrite it?`)) {
                return;
            }
            systems[existingIdx] = newSystem;
        } else {
            systems.push(newSystem);
        }
    }

    // Save and close
    const sessionKey = sessionStorage.getItem('erp_session_key');
    if (sessionKey) {
        encryptData(JSON.stringify(systems), sessionKey).then(encrypted => {
            localStorage.setItem('custom_erp_systems', JSON.stringify(encrypted));
            closeModal();
            setupCategoryMultiSelectDropdown();
            filterSystems();
        }).catch(err => {
            console.error("Failed to encrypt and save systems:", err);
            alert("Error saving data. Please check your session.");
        });
        return;
    }
}

window.saveNewVendor = saveNewVendor;

// Setup CSV Toolbar (Import / Export)
function setupCSVToolbar() {
    const btnExport = document.getElementById('btnExportCSV');
    const btnImportTrigger = document.getElementById('btnImportTrigger');
    const csvFileInput = document.getElementById('csvFileInput');

    // Export Notes
    if (btnExport) {
        btnExport.addEventListener('click', () => {
            exportNotesToCSV();
        });
    }

    // Import Notes Trigger
    if (btnImportTrigger) {
        btnImportTrigger.addEventListener('click', () => {
            csvFileInput.click();
        });
    }

    // File Input change
    if (csvFileInput) {
        csvFileInput.addEventListener('change', (e) => {
            const file = e.target.files[0];
            if (!file) return;

            const reader = new FileReader();
            reader.onload = function (evt) {
                const csvText = evt.target.result;
                importNotesFromCSV(csvText);
                csvFileInput.value = ''; // Reset file input
            };
            reader.readAsText(file);
        });
    }

    // Add Vendor Button
    const btnAddVendor = document.getElementById('btnAddVendor');
    if (btnAddVendor) {
        btnAddVendor.addEventListener('click', () => {
            openAddVendorModal();
        });
    }

    // Export JSON
    const btnExportJSON = document.getElementById('btnExportJSON');
    if (btnExportJSON) {
        btnExportJSON.addEventListener('click', () => {
            exportSystemsToJSON();
        });
    }

    // Import JSON Trigger
    const btnImportJSONTrigger = document.getElementById('btnImportJSONTrigger');
    const jsonFileInput = document.getElementById('jsonFileInput');
    if (btnImportJSONTrigger && jsonFileInput) {
        btnImportJSONTrigger.addEventListener('click', () => {
            jsonFileInput.click();
        });

        jsonFileInput.addEventListener('change', (e) => {
            const file = e.target.files[0];
            if (!file) return;

            const reader = new FileReader();
            reader.onload = function (evt) {
                const jsonText = evt.target.result;
                importSystemsFromJSON(jsonText);
                jsonFileInput.value = ''; // Reset file input
            };
            reader.readAsText(file);
        });
    }

    // Reset Defaults
    const btnResetDefaults = document.getElementById('btnResetDefaults');
    if (btnResetDefaults) {
        btnResetDefaults.addEventListener('click', () => {
            resetToDefaults();
        });
    }
}

// CSV Export Utility
function exportNotesToCSV() {
    const rows = [
        ['System Name', 'System Notes', 'VAR Name', 'VAR Notes']
    ];

    systems.forEach(system => {
        const systemNotes = localStorage.getItem(getERPNotesKey(system.name)) || "";

        // Add row for ERP system note itself
        rows.push([system.name, systemNotes, '', '']);

        // Add rows for each VAR note
        if (system.ukVars && system.ukVars.length > 0) {
            system.ukVars.forEach(v => {
                const varNotes = localStorage.getItem(getVARNotesKey(system.name, v.name)) || "";
                rows.push([system.name, '', v.name, varNotes]);
            });
        }
    });

    // Generate CSV contents
    const csvContent = rows.map(row =>
        row.map(cell => {
            if (cell === undefined || cell === null) return '""';
            // Escape double quotes by doubling them, wrap in double quotes
            const escaped = String(cell).replace(/"/g, '""');
            return `"${escaped}"`;
        }).join(',')
    ).join('\n');

    // Create file and download
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `manufacturing_erp_mrp_notes_${new Date().toISOString().slice(0, 10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
}

// CSV Import Utility
function importNotesFromCSV(csvText) {
    try {
        const parsedRows = parseCSV(csvText);
        if (parsedRows.length <= 1) {
            alert("The loaded CSV file is empty or invalid.");
            return;
        }

        // Validate Header Row
        const headers = parsedRows[0].map(h => h.trim().toLowerCase());
        const systemIdx = headers.indexOf('system name');
        const systemNotesIdx = headers.indexOf('system notes');
        const varIdx = headers.indexOf('var name');
        const varNotesIdx = headers.indexOf('var notes');

        if (systemIdx === -1 || systemNotesIdx === -1 || varIdx === -1 || varNotesIdx === -1) {
            alert("Invalid CSV format. CSV must contain the columns: 'System Name', 'System Notes', 'VAR Name', 'VAR Notes'");
            return;
        }

        let importCount = 0;

        for (let i = 1; i < parsedRows.length; i++) {
            const row = parsedRows[i];
            if (row.length < 2) continue; // skip incomplete rows

            const sysName = row[systemIdx] ? row[systemIdx].trim() : '';
            const sysNotes = row[systemNotesIdx] ? row[systemNotesIdx].trim() : '';
            const varName = row[varIdx] ? row[varIdx].trim() : '';
            const varNotes = row[varNotesIdx] ? row[varNotesIdx].trim() : '';

            if (!sysName) continue;

            // Find matching system in our database (case-insensitive)
            const matchedSystem = systems.find(s => s.name.toLowerCase() === sysName.toLowerCase());
            if (!matchedSystem) {
                console.warn(`System name from CSV doesn't match any system in the database: "${sysName}"`);
                continue;
            }

            // If system notes are present, import them
            if (sysNotes) {
                localStorage.setItem(getERPNotesKey(matchedSystem.name), sysNotes);
                importCount++;
            }

            // If VAR notes are present and a VAR is specified, import them
            if (varName && varNotes) {
                // Find matching VAR on this system (case-insensitive)
                const matchedVar = matchedSystem.ukVars ?
                    matchedSystem.ukVars.find(v => v.name.toLowerCase() === varName.toLowerCase()) : null;

                if (matchedVar) {
                    localStorage.setItem(getVARNotesKey(matchedSystem.name, matchedVar.name), varNotes);
                    importCount++;
                } else {
                    console.warn(`VAR "${varName}" not found on system "${matchedSystem.name}"`);
                }
            }
        }

        alert(`Success! Successfully imported and merged ${importCount} note entries.`);
        filterSystems(); // Re-render the cards with the new notes
    } catch (e) {
        console.error("CSV Import Error: ", e);
        alert("An error occurred while parsing the CSV file. Please make sure the format is correct.");
    }
}

// Robust CSV Line Parser (RFC 4180-compliant)
function parseCSV(text) {
    const lines = [];
    let row = [""];
    let inQuotes = false;

    for (let i = 0; i < text.length; i++) {
        let c = text[i];
        let next = text[i + 1];

        if (c === '"') {
            if (inQuotes && next === '"') {
                row[row.length - 1] += '"';
                i++; // Skip next quote
            } else {
                inQuotes = !inQuotes;
            }
        } else if (c === ',' && !inQuotes) {
            row.push("");
        } else if ((c === '\r' || c === '\n') && !inQuotes) {
            if (c === '\r' && next === '\n') {
                i++; // Skip LF in CRLF
            }
            lines.push(row);
            row = [""];
        } else {
            row[row.length - 1] += c;
        }
    }

    if (row.length > 1 || row[0] !== "") {
        lines.push(row);
    }

    return lines;
}

// JSON Export Utility
function exportSystemsToJSON() {
    const dataStr = JSON.stringify(systems, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `data_${new Date().toISOString().slice(0, 10)}.json`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
}

// JSON Import Utility
function importSystemsFromJSON(jsonText) {
    try {
        const parsed = JSON.parse(jsonText);
        if (!Array.isArray(parsed)) {
            alert("Invalid JSON format. The file must contain a JSON array of ERP systems.");
            return;
        }

        // Schema validation
        const isValid = parsed.every(item => {
            return item && typeof item === 'object' && typeof item.name === 'string';
        });

        if (!isValid) {
            alert("Invalid JSON schema. Each vendor record must at least have a 'name' field.");
            return;
        }

        // Validate and clean up optional properties to prevent rendering crashes
        const validated = parsed.map(item => {
            return {
                name: item.name,
                categories: Array.isArray(item.categories) ? item.categories : (item.category ? [item.category] : ["Small Business"]),
                sectors: Array.isArray(item.sectors) ? item.sectors : [],
                size: item.size || "small",
                deployment: item.deployment || "Cloud (SaaS)",
                location: item.location || "UK Support",
                financialStability: item.financialStability || "Moderate",
                strengths: Array.isArray(item.strengths) ? item.strengths : [],
                contact: item.contact || { website: "", email: "", phone: "" },
                ukVars: Array.isArray(item.ukVars) ? item.ukVars : [],
                idcCapabilities: item.idcCapabilities !== undefined ? parseInt(item.idcCapabilities) : undefined,
                idcStrategies: item.idcStrategies !== undefined ? parseInt(item.idcStrategies) : undefined,
                idcMarketShare: item.idcMarketShare !== undefined ? parseInt(item.idcMarketShare) : undefined
            };
        });

        if (confirm(`Are you sure you want to import ${validated.length} vendors? This will replace your current vendor list.`)) {
            systems = validated;
            const sessionKey = sessionStorage.getItem('erp_session_key');
            if (sessionKey) {
                encryptData(JSON.stringify(systems), sessionKey).then(encrypted => {
                    localStorage.setItem('custom_erp_systems', JSON.stringify(encrypted));
                    alert("Successfully imported systems!");
                    setupCategoryMultiSelectDropdown();
                    filterSystems();
                }).catch(err => {
                    console.error("Failed to encrypt and save systems:", err);
                    alert("Error saving imported data.");
                });
            }
        }
    } catch (e) {
        console.error("JSON Import Error:", e);
        alert("An error occurred while parsing the JSON file. Please check that it is valid JSON.");
    }
}

// Reset Defaults Utility
function resetToDefaults() {
    if (confirm("Are you sure you want to reset the vendor list to the default research data? This will overwrite any custom vendors you added, but will NOT delete your notes.")) {
        localStorage.removeItem('custom_erp_systems');
        systems = JSON.parse(JSON.stringify(defaultSystems));
        alert("Vendor list has been reset to defaults!");
        setupCategoryMultiSelectDropdown();
        filterSystems();
    }
}

// Sanitization & Safety Helpers
function escapeHTML(str) {
    if (!str) return "";
    return str
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
}

function escapeJS(str) {
    if (!str) return "";
    return str.replace(/'/g, "\\'").replace(/"/g, '\\"');
}

// Bind load event
window.addEventListener('DOMContentLoaded', init);
